import { describe, expect, it } from 'vitest';

import {
  activeSignatures,
  activesDistinct,
  adist,
  admitOverlap,
  countActive,
  minConcurrent,
  overlapFrame,
  sameSpeakerFrame,
  sepThreshold,
  singleFrame,
  SpeakerOverlapMaster,
  type Frame,
} from '../src/speaker-overlap-structure';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 100, 400]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(100, 400)).toBe(300);
    expect(adist(400, 100)).toBe(300);
    expect(adist(100, 110)).toBe(10);
    expect(adist(110, 100)).toBe(10);
  });
});

describe('countActive (mirrors countActive)', () => {
  it('counts only the active sources', () => {
    expect(countActive(overlapFrame)).toBe(2);
    expect(countActive(singleFrame)).toBe(1);
    expect(countActive(sameSpeakerFrame)).toBe(2);
  });

  it('is zero on an empty frame', () => {
    expect(countActive([])).toBe(0);
  });
});

describe('activeSignatures (mirrors activeSignatures)', () => {
  it('keeps only the signatures of active sources, in order', () => {
    expect(activeSignatures(overlapFrame)).toEqual([100, 400]);
    expect(activeSignatures(singleFrame)).toEqual([100]);
    expect(activeSignatures(sameSpeakerFrame)).toEqual([100, 110]);
  });
});

describe('activesDistinct (mirrors activesDistinctB)', () => {
  it('is true when active signatures are pairwise separated beyond threshold', () => {
    // gap 300 > 50
    expect(activesDistinct(sepThreshold, overlapFrame)).toBe(true);
  });

  it('is false when two active signatures sit within threshold (double-count)', () => {
    // gap 10 <= 50
    expect(activesDistinct(sepThreshold, sameSpeakerFrame)).toBe(false);
  });

  it('is vacuously true with fewer than two active signatures', () => {
    expect(activesDistinct(sepThreshold, singleFrame)).toBe(true);
    expect(activesDistinct(sepThreshold, [])).toBe(true);
  });

  it('uses a strict threshold (equality at the boundary is not distinct)', () => {
    const frame: Frame = [
      { signature: 0, active: true },
      { signature: 50, active: true },
    ];
    // adist 0 50 = 50, not > 50 -> not distinct
    expect(activesDistinct(50, frame)).toBe(false);
    expect(activesDistinct(49, frame)).toBe(true);
  });
});

describe('promotion check: admitOverlap', () => {
  it('admits a genuine two-speaker overlap frame', () => {
    const a = admitOverlap(overlapFrame, { sepThreshold, minConcurrent });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.activeCount).toBe(2);
    expect(a.concurrent).toBe(true);
    expect(a.distinct).toBe(true);
  });

  it('withholds a sequential / single-active frame on the concurrency gate', () => {
    // mirrors single_speaker_rejected
    const a = admitOverlap(singleFrame, { sepThreshold, minConcurrent });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('single_speaker');
    expect(a.activeCount).toBe(1);
    expect(a.concurrent).toBe(false);
    expect(a.summary).toContain('single speaker');
  });

  it('withholds a same-speaker double-count on the distinctness gate', () => {
    // mirrors same_speaker_double_not_overlap: concurrency met, distinctness fails
    const a = admitOverlap(sameSpeakerFrame, { sepThreshold, minConcurrent });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('same_speaker_doublecount');
    expect(a.activeCount).toBe(2);
    expect(a.concurrent).toBe(true);
    expect(a.distinct).toBe(false);
    expect(a.summary).toContain('same-speaker');
  });

  it('reports observation_only on an empty frame', () => {
    const a = admitOverlap([], { sepThreshold, minConcurrent });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('empty_frame');
  });
});

describe('SpeakerOverlapMaster (mirrors speaker_overlap_master)', () => {
  it('every boundary witness holds', () => {
    expect(SpeakerOverlapMaster.overlapFrameCountActive).toBe(true);
    expect(SpeakerOverlapMaster.singleFrameCountActive).toBe(true);
    expect(SpeakerOverlapMaster.sameSpeakerFrameCountActive).toBe(true);
    expect(SpeakerOverlapMaster.overlapFrameDistinct).toBe(true);
    expect(SpeakerOverlapMaster.sameSpeakerFrameNotDistinct).toBe(true);
    expect(SpeakerOverlapMaster.overlapAdmitted).toBe(true);
    expect(SpeakerOverlapMaster.singleSpeakerRejected).toBe(true);
    expect(SpeakerOverlapMaster.sameSpeakerRejected).toBe(true);
    expect(SpeakerOverlapMaster.overlapVsSequential).toBe(true);
  });
});
